import { Card, Stack, Row, Text, Box } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function GeneratedComponent(props: Props) {
  const { city, temperature, condition, humidity, windSpeed, unit, forecast } = props;

  // Map weather conditions to emoji
  const getWeatherEmoji = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloud')) return '☁️';
    if (condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('wind')) return '💨';
    if (condLower.includes('fog') || condLower.includes('mist')) return '🌫️';
    return '🌤️'; // default
  };

  return (
    <Card
      padding={24}
      shadow="md"
      style={{
        background: 'linear-gradient(135deg, var(--ggui-color-primary-50, #f0f9ff), var(--ggui-color-primary-100, #e0f2fe))',
        borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
      }}
    >
      <Stack direction="vertical" gap={24}>
        {/* Header with city name */}
        <div>
          <Text
            variant="h2"
            color="var(--ggui-color-primary-900, #0c4a6e)"
            weight="bold"
          >
            {city}
          </Text>
        </div>

        {/* Current weather section */}
        <Stack direction="horizontal" gap={24} align="center" justify="between">
          {/* Temperature and condition */}
          <Stack direction="vertical" gap={8} align="start">
            <div style={{ fontSize: '64px', lineHeight: 1 }}>
              {getWeatherEmoji(condition)}
            </div>
            <Text
              variant="h1"
              color="var(--ggui-color-primary-900, #0c4a6e)"
              weight="bold"
            >
              {temperature}°{unit}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="semibold"
            >
              {condition}
            </Text>
          </Stack>

          {/* Humidity and wind speed */}
          <Stack direction="vertical" gap={16}>
            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-primary-100, #e0f2fe)"
              style={{
                borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
              }}
            >
              <Stack direction="vertical" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <Text
                  variant="h3"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                  weight="semibold"
                >
                  {humidity}%
                </Text>
              </Stack>
            </Box>

            <Box
              padding={12}
              borderRadius="var(--ggui-shape-radius-md, 8px)"
              background="var(--ggui-color-primary-100, #e0f2fe)"
              style={{
                borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
              }}
            >
              <Stack direction="vertical" gap={4}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  weight="medium"
                >
                  Wind Speed
                </Text>
                <Text
                  variant="h3"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                  weight="semibold"
                >
                  {windSpeed} mph
                </Text>
              </Stack>
            </Box>
          </Stack>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-primary-200, #bae6fd)',
          }}
        />

        {/* 5-day forecast strip */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-primary-700, #0369a1)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>
          <Row
            gap={8}
            wrap={true}
            justify="start"
            style={{
              overflow: 'auto',
              paddingBottom: '4px',
            }}
          >
            {forecast.map((day, idx) => {
              const key = day.day + idx;
              return (
                <Box
                  key={key}
                  padding={12}
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  background="var(--ggui-color-primary-50, #f0f9ff)"
                  style={{
                    border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
                    minWidth: '90px',
                    textAlign: 'center',
                    flexShrink: 0,
                  }}
                >
                  <Stack direction="vertical" gap={6} align="center">
                    <Text
                      variant="label"
                      color="var(--ggui-color-primary-700, #0369a1)"
                      weight="semibold"
                    >
                      {day.day}
                    </Text>
                    <div style={{ fontSize: '24px', lineHeight: 1 }}>
                      {day.icon}
                    </div>
                    <Stack direction="horizontal" gap={4} align="center">
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-900, #0c4a6e)"
                        weight="bold"
                      >
                        {day.high}°
                      </Text>
                      <Text
                        variant="caption"
                        color="var(--ggui-color-primary-600, #0284c7)"
                      >
                        {day.low}°
                      </Text>
                    </Stack>
                  </Stack>
                </Box>
              );
            })}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

import { useState, useMemo } from 'react';
import { Container, Card, Stack, Row, Text, Input, Icon, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  electronConfiguration: string;
  row: number;
  col: number;
}

interface Props {
  elements: Element[];
}

// Category to color mapping
const categoryColorMap: Record<string, string> = {
  'Alkali Metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'Alkaline Earth Metal': 'var(--ggui-color-primary-400, #38bdf8)',
  'Lanthanide': 'var(--ggui-color-warning-500, #f59e0b)',
  'Actinide': 'var(--ggui-color-error-500, #ef4444)',
  'Transition Metal': 'var(--ggui-color-success-500, #22c55e)',
  'Post-transition Metal': 'var(--ggui-color-primary-300, #7dd3fc)',
  'Metalloid': 'var(--ggui-color-warning-400, #fbbf24)',
  'Nonmetal': 'var(--ggui-color-neutral-400, #9ca3af)',
  'Halogen': 'var(--ggui-color-warning-600, #d97706)',
  'Noble Gas': 'var(--ggui-color-primary-600, #0284c7)',
};

export default function PeriodicTable({ elements }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);
  const { motionEnabled } = useMotion();

  // Filter elements based on search
  const filteredElements = useMemo(() => {
    if (!searchTerm.trim()) return elements;
    const term = searchTerm.toLowerCase();
    return elements.filter(el =>
      el.name.toLowerCase().includes(term) ||
      el.symbol.toLowerCase().includes(term)
    );
  }, [searchTerm, elements]);

  // Get unique categories for legend
  const uniqueCategories = useMemo(() => {
    return Array.from(new Set(elements.map(el => el.category))).sort();
  }, [elements]);

  // Build grid with proper positioning
  const gridCells: (Element | null)[][] = Array.from({ length: 7 }, () =>
    Array.from({ length: 18 }, () => null)
  );

  filteredElements.forEach(element => {
    const rowIdx = element.row - 1;
    const colIdx = element.col - 1;
    if (rowIdx >= 0 && rowIdx < 7 && colIdx >= 0 && colIdx < 18) {
      gridCells[rowIdx][colIdx] = element;
    }
  });

  const getElementColor = (category: string): string => {
    return categoryColorMap[category] || 'var(--ggui-color-neutral-200, #e5e7eb)';
  };

  const getCellKey = (rowIdx: number, colIdx: number): string => {
    return rowIdx + '-' + colIdx;
  };

  const getDelayMs = (rowIdx: number, colIdx: number): number => {
    return (rowIdx * 18 + colIdx) * 10;
  };

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
        <Stack direction="vertical" gap={24}>
          {/* Title */}
          <div>
            <Text variant="h1" color="var(--ggui-color-onSurface, #18181b)">
              Interactive Periodic Table
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Click on any element to view details
            </Text>
          </div>

          {/* Search Input */}
          <Input
            label="Search Elements"
            placeholder="Search by element name or symbol..."
            value={searchTerm}
            onChange={setSearchTerm}
            leftIcon={<Icon name="search" size={18} />}
          />

          {/* Legend */}
          <Card padding="var(--ggui-spacing-4, 16px)">
            <Stack direction="vertical" gap={12}>
              <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                Element Categories
              </Text>
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(180px, 1fr))',
                gap: 'var(--ggui-spacing-3, 12px)',
              }}>
                {uniqueCategories.map(category => (
                  <Row key={category} gap={8} align="center">
                    <div
                      style={{
                        width: 24,
                        height: 24,
                        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                        backgroundColor: getElementColor(category),
                        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                        flexShrink: 0,
                      }}
                    />
                    <Text variant="caption" color="var(--ggui-color-onSurface, #18181b)">
                      {category}
                    </Text>
                  </Row>
                ))}
              </div>
            </Stack>
          </Card>

          {/* Periodic Table Grid */}
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2, 8px)',
            padding: 'var(--ggui-spacing-4, 16px)',
            backgroundColor: 'var(--ggui-color-surface, #fafafa)',
            borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
            border: '1px solid var(--ggui-color-outline, #d4d4d8)',
          }}>
            {gridCells.map((row, rowIdx) =>
              row.map((element, colIdx) => {
                const cellKey = getCellKey(rowIdx, colIdx);
                const delayMs = getDelayMs(rowIdx, colIdx);
                return (
                  <div
                    key={cellKey}
                    onClick={() => element && setSelectedElement(element)}
                    style={{
                      cursor: element ? 'pointer' : 'default',
                      animation: motionEnabled && element ? animation.scaleIn : 'none',
                      animationDelay: motionEnabled ? delayMs + 'ms' : '0ms',
                    }}
                  >
                    {element ? (
                      <Card
                        padding="var(--ggui-spacing-2, 8px)"
                        shadow={selectedElement?.atomicNumber === element.atomicNumber ? 'lg' : 'sm'}
                        border
                        style={{
                          backgroundColor: getElementColor(element.category),
                          cursor: 'pointer',
                          transition: 'all 200ms cubic-bezier(0.4, 0, 0.2, 1)',
                          minHeight: '80px',
                          display: 'flex',
                          flexDirection: 'column',
                          justifyContent: 'space-between',
                          border: selectedElement?.atomicNumber === element.atomicNumber
                            ? '2px solid var(--ggui-color-onSurface, #18181b)'
                            : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                          transform: selectedElement?.atomicNumber === element.atomicNumber
                            ? 'scale(1.05)'
                            : 'scale(1)',
                        }}
                        onMouseEnter={(e) => {
                          if (selectedElement?.atomicNumber !== element.atomicNumber) {
                            const elem = e.currentTarget as HTMLElement;
                            elem.style.transform = 'scale(1.02)';
                            elem.style.boxShadow = 'var(--ggui-shape-shadow-md, 0 4px 6px -1px rgba(0,0,0,0.1))';
                          }
                        }}
                        onMouseLeave={(e) => {
                          if (selectedElement?.atomicNumber !== element.atomicNumber) {
                            const elem = e.currentTarget as HTMLElement;
                            elem.style.transform = 'scale(1)';
                            elem.style.boxShadow = 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))';
                          }
                        }}
                      >
                        <Text
                          variant="caption"
                          weight="semibold"
                          color="var(--ggui-color-onSurface, #18181b)"
                          align="left"
                          style={{ fontSize: 'var(--ggui-font-size-xs, 12px)' }}
                        >
                          {element.atomicNumber}
                        </Text>
                        <Text
                          variant="h3"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                          align="center"
                          style={{ fontSize: 'var(--ggui-font-size-xl, 20px)', margin: '4px 0' }}
                        >
                          {element.symbol}
                        </Text>
                        <Text
                          variant="caption"
                          color="var(--ggui-color-onSurface, #18181b)"
                          align="center"
                          style={{ fontSize: 'var(--ggui-font-size-xs, 10px)', opacity: 0.7 }}
                        >
                          {element.name}
                        </Text>
                      </Card>
                    ) : (
                      <div />
                    )}
                  </div>
                );
              })
            )}
          </div>

          {/* Detail Panel */}
          {selectedElement && (
            <Card
              padding="var(--ggui-spacing-6, 24px)"
              shadow="lg"
              style={{
                animation: motionEnabled ? animation.slideInUp : 'none',
                backgroundColor: 'var(--ggui-color-container, #ede9fe)',
                borderLeft: '4px solid ' + getElementColor(selectedElement.category),
              }}
            >
              <Stack direction="vertical" gap={16}>
                <Row justify="between" align="start">
                  <div>
                    <Text variant="h2" color="var(--ggui-color-onContainer, #4c1d95)">
                      {selectedElement.name}
                    </Text>
                    <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {selectedElement.category}
                    </Text>
                  </div>
                  <button
                    onClick={() => setSelectedElement(null)}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      padding: 'var(--ggui-spacing-2, 8px)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      color: 'var(--ggui-color-onContainer, #4c1d95)',
                    }}
                  >
                    <Icon name="x" size={24} />
                  </button>
                </Row>

                <div style={{
                  display: 'grid',
                  gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                  gap: 'var(--ggui-spacing-4, 16px)',
                }}>
                  <div>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onContainer, #4c1d95)">
                      Atomic Number
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-onContainer, #4c1d95)">
                      {selectedElement.atomicNumber}
                    </Text>
                  </div>
                  <div>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onContainer, #4c1d95)">
                      Symbol
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-onContainer, #4c1d95)">
                      {selectedElement.symbol}
                    </Text>
                  </div>
                  <div>
                    <Text variant="label" weight="semibold" color="var(--ggui-color-onContainer, #4c1d95)">
                      Atomic Weight
                    </Text>
                    <Text variant="h3" color="var(--ggui-color-onContainer, #4c1d95)">
                      {selectedElement.atomicWeight.toFixed(3)}
                    </Text>
                  </div>
                </div>

                <div>
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onContainer, #4c1d95)">
                    Electron Configuration
                  </Text>
                  <Text
                    variant="body"
                    color="var(--ggui-color-onContainer, #4c1d95)"
                    style={{
                      fontFamily: 'monospace',
                      marginTop: 'var(--ggui-spacing-2, 8px)',
                      padding: 'var(--ggui-spacing-2, 8px)',
                      backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                      borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                    }}
                  >
                    {selectedElement.electronConfiguration}
                  </Text>
                </div>
              </Stack>
            </Card>
          )}

          {/* Empty State */}
          {filteredElements.length === 0 && (
            <Card padding="var(--ggui-spacing-8, 32px)" shadow="none">
              <Stack direction="vertical" gap={8} align="center">
                <Icon name="search" size={32} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                <Text variant="body" align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No elements found matching "{searchTerm}"
                </Text>
              </Stack>
            </Card>
          )}
        </Stack>
      </Container>
    </>
  );
}

import React from "react";
import { Card, Stack, Text, Button, Input } from "@ggui-ai/design/primitives";

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

const conditionGradients: Record<string, string> = {
  sunny: "linear-gradient(135deg, var(--ggui-color-warning, #f59e0b), var(--ggui-color-primary, #3b82f6))",
  cloudy: "linear-gradient(135deg, var(--ggui-color-surface-variant, #94a3b8), var(--ggui-color-surface, #e2e8f0))",
  rainy: "linear-gradient(135deg, var(--ggui-color-secondary, #6366f1), var(--ggui-color-primary, #3b82f6))",
  snowy: "linear-gradient(135deg, var(--ggui-color-surface, #f8fafc), var(--ggui-color-primary, #3b82f6))",
  stormy: "linear-gradient(135deg, var(--ggui-color-surface-variant, #334155), var(--ggui-color-secondary, #6366f1))",
  windy: "linear-gradient(135deg, var(--ggui-color-primary, #3b82f6), var(--ggui-color-secondary, #6366f1))",
};

function getConditionKey(condition: string): string {
  const lower = condition.toLowerCase();
  if (lower.includes("sun") || lower.includes("clear")) return "sunny";
  if (lower.includes("rain") || lower.includes("shower") || lower.includes("drizzle")) return "rainy";
  if (lower.includes("snow") || lower.includes("sleet") || lower.includes("frost")) return "snowy";
  if (lower.includes("storm") || lower.includes("thunder") || lower.includes("lightning")) return "stormy";
  if (lower.includes("wind") || lower.includes("breeze") || lower.includes("gust")) return "windy";
  return "cloudy";
}

function getConditionEmoji(condition: string): string {
  const key = getConditionKey(condition);
  const map: Record<string, string> = {
    sunny: "☀️",
    cloudy: "⛅",
    rainy: "🌧️",
    snowy: "❄️",
    stormy: "⛈️",
    windy: "💨",
  };
  return map[key] ?? "🌡️";
}

function buildForecastLabel(day: string, icon: string, high: number, unit: string, low: number): string {
  return day + ": " + icon + ", high " + String(high) + "°" + unit + ", low " + String(low) + "°" + unit;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit,
    forecast,
  } = props;

  const conditionKey = getConditionKey(condition);
  const conditionEmoji = getConditionEmoji(condition);
  const gradient = conditionGradients[conditionKey] ?? conditionGradients["cloudy"];
  const conditionAriaLabel = "Weather condition: " + condition;

  return (
    <div
      style={{
        padding: "var(--ggui-spacing-4, 16px)",
        maxWidth: "420px",
        width: "100%",
        margin: "0 auto",
        fontFamily: "var(--ggui-font-family, sans-serif)",
      }}
    >
      <Card
        variant="elevated"
        style={{
          overflow: "hidden",
          borderRadius: "var(--ggui-radius-xl, 20px)",
          border: "1px solid var(--ggui-color-outline, #e2e8f0)",
        }}
      >
        {/* Hero section with gradient */}
        <div
          style={{
            background: gradient,
            padding: "var(--ggui-spacing-8, 32px) var(--ggui-spacing-6, 24px) var(--ggui-spacing-6, 24px)",
            position: "relative",
          }}
        >
          {/* City name */}
          <Stack direction="horizontal" gap="2" align="center">
            <span style={{ fontSize: "var(--ggui-font-size-sm, 14px)", opacity: 0.85 }}>📍</span>
            <Text
              variant="label"
              style={{
                color: "var(--ggui-color-onPrimary, #fff)",
                fontWeight: "600",
                letterSpacing: "0.05em",
                textTransform: "uppercase",
                fontSize: "var(--ggui-font-size-sm, 13px)",
              }}
            >
              {city}
            </Text>
          </Stack>

          {/* Temperature & Condition */}
          <Stack direction="horizontal" gap="4" align="center" style={{ marginTop: "var(--ggui-spacing-4, 16px)" }}>
            <div>
              <Text
                variant="display"
                style={{
                  color: "var(--ggui-color-onPrimary, #fff)",
                  fontSize: "var(--ggui-font-size-6xl, 80px)",
                  fontWeight: "700",
                  lineHeight: "1",
                  letterSpacing: "-0.03em",
                }}
              >
                {temperature}°{unit}
              </Text>
              <Text
                variant="body"
                style={{
                  color: "var(--ggui-color-onPrimary, #fff)",
                  opacity: 0.9,
                  marginTop: "var(--ggui-spacing-1, 4px)",
                  fontSize: "var(--ggui-font-size-lg, 18px)",
                  fontWeight: "500",
                }}
              >
                {condition}
              </Text>
            </div>
            <div
              style={{
                marginLeft: "auto",
                fontSize: "var(--ggui-font-size-7xl, 72px)",
                lineHeight: "1",
                userSelect: "none",
              }}
              aria-label={conditionAriaLabel}
              role="img"
            >
              {conditionEmoji}
            </div>
          </Stack>
        </div>

        {/* Stats row */}
        <div
          style={{
            padding: "var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px)",
            background: "var(--ggui-color-surface, #fff)",
            borderBottom: "1px solid var(--ggui-color-outline, #e2e8f0)",
          }}
        >
          <Stack direction="horizontal" gap="4" align="center">
            {/* Humidity */}
            <div
              style={{
                flex: 1,
                textAlign: "center",
                padding: "var(--ggui-spacing-3, 12px)",
                borderRadius: "var(--ggui-radius-lg, 12px)",
                background: "var(--ggui-color-surface-variant, #f1f5f9)",
              }}
            >
              <div style={{ fontSize: "var(--ggui-font-size-2xl, 24px)", marginBottom: "var(--ggui-spacing-1, 4px)" }} role="img" aria-label="Humidity">💧</div>
              <Text
                variant="heading"
                style={{
                  color: "var(--ggui-color-onSurface, #1e293b)",
                  fontWeight: "700",
                  fontSize: "var(--ggui-font-size-lg, 18px)",
                }}
              >
                {humidity}%
              </Text>
              <Text
                variant="caption"
                style={{
                  color: "var(--ggui-color-onSurface-variant, #64748b)",
                  fontSize: "var(--ggui-font-size-xs, 11px)",
                  textTransform: "uppercase",
                  letterSpacing: "0.05em",
                }}
              >
                Humidity
              </Text>
            </div>

            {/* Divider */}
            <div
              style={{
                width: "1px",
                height: "48px",
                background: "var(--ggui-color-outline, #e2e8f0)",
              }}
              aria-hidden="true"
            />

            {/* Wind */}
            <div
              style={{
                flex: 1,
                textAlign: "center",
                padding: "var(--ggui-spacing-3, 12px)",
                borderRadius: "var(--ggui-radius-lg, 12px)",
                background: "var(--ggui-color-surface-variant, #f1f5f9)",
              }}
            >
              <div style={{ fontSize: "var(--ggui-font-size-2xl, 24px)", marginBottom: "var(--ggui-spacing-1, 4px)" }} role="img" aria-label="Wind speed">🌬️</div>
              <Text
                variant="heading"
                style={{
                  color: "var(--ggui-color-onSurface, #1e293b)",
                  fontWeight: "700",
                  fontSize: "var(--ggui-font-size-lg, 18px)",
                }}
              >
                {windSpeed} km/h
              </Text>
              <Text
                variant="caption"
                style={{
                  color: "var(--ggui-color-onSurface-variant, #64748b)",
                  fontSize: "var(--ggui-font-size-xs, 11px)",
                  textTransform: "uppercase",
                  letterSpacing: "0.05em",
                }}
              >
                Wind Speed
              </Text>
            </div>
          </Stack>
        </div>

        {/* 5-day forecast strip */}
        <div
          style={{
            padding: "var(--ggui-spacing-4, 16px) var(--ggui-spacing-6, 24px) var(--ggui-spacing-5, 20px)",
            background: "var(--ggui-color-surface, #fff)",
          }}
        >
          <Text
            variant="label"
            style={{
              color: "var(--ggui-color-onSurface-variant, #64748b)",
              fontWeight: "600",
              fontSize: "var(--ggui-font-size-xs, 11px)",
              textTransform: "uppercase",
              letterSpacing: "0.08em",
              marginBottom: "var(--ggui-spacing-3, 12px)",
              display: "block",
            }}
          >
            5-Day Forecast
          </Text>
          <Stack direction="horizontal" gap="2" align="stretch">
            {forecast.map((item) => (
              <div
                key={item.day}
                style={{
                  flex: 1,
                  textAlign: "center",
                  padding: "var(--ggui-spacing-3, 10px) var(--ggui-spacing-2, 6px)",
                  borderRadius: "var(--ggui-radius-lg, 12px)",
                  background: "var(--ggui-color-surface-variant, #f8fafc)",
                  border: "1px solid var(--ggui-color-outline, #e2e8f0)",
                  transition: "all 0.2s ease",
                  cursor: "default",
                }}
                onMouseEnter={(e) => {
                  const el = e.currentTarget as HTMLDivElement;
                  el.style.background = "var(--ggui-color-primary-container, #dbeafe)";
                  el.style.borderColor = "var(--ggui-color-primary, #3b82f6)";
                  el.style.transform = "translateY(-2px)";
                  el.style.boxShadow = "0 4px 12px var(--ggui-color-shadow, #00000014)";
                }}
                onMouseLeave={(e) => {
                  const el = e.currentTarget as HTMLDivElement;
                  el.style.background = "var(--ggui-color-surface-variant, #f8fafc)";
                  el.style.borderColor = "var(--ggui-color-outline, #e2e8f0)";
                  el.style.transform = "translateY(0)";
                  el.style.boxShadow = "none";
                }}
                role="listitem"
                aria-label={buildForecastLabel(item.day, item.icon, item.high, unit, item.low)}
                tabIndex={0}
              >
                <Text
                  variant="caption"
                  style={{
                    color: "var(--ggui-color-onSurface-variant, #64748b)",
                    fontWeight: "600",
                    fontSize: "var(--ggui-font-size-xs, 11px)",
                    textTransform: "uppercase",
                    letterSpacing: "0.05em",
                    display: "block",
                  }}
                >
                  {item.day}
                </Text>
                <div
                  style={{
                    fontSize: "var(--ggui-font-size-2xl, 22px)",
                    margin: "var(--ggui-spacing-2, 6px) 0",
                    userSelect: "none",
                  }}
                  role="img"
                  aria-hidden="true"
                >
                  {item.icon}
                </div>
                <Text
                  variant="body"
                  style={{
                    color: "var(--ggui-color-onSurface, #1e293b)",
                    fontWeight: "700",
                    fontSize: "var(--ggui-font-size-sm, 13px)",
                    display: "block",
                  }}
                >
                  {item.high}°
                </Text>
                <Text
                  variant="caption"
                  style={{
                    color: "var(--ggui-color-onSurface-variant, #94a3b8)",
                    fontWeight: "500",
                    fontSize: "var(--ggui-font-size-xs, 11px)",
                    display: "block",
                  }}
                >
                  {item.low}°
                </Text>
              </div>
            ))}
          </Stack>
        </div>
      </Card>
    </div>
  );
}
